import{_ as o,o as t,c as i,a2 as c}from"./chunks/framework.Bk_3gXAz.js";const u=JSON.parse('{"title":"cm-start","description":"Start the CM Workflow to execute your objective from idea to production code.","frontmatter":{"title":"cm-start","name":"cm-start","description":"Start the CM Workflow to execute your objective from idea to production code."},"headers":[],"relativePath":"skills/cm-start.md","filePath":"skills/cm-start.md"}'),l={name:"skills/cm-start.md"};function r(n,e,d,s,a,p){return t(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="command-cm-start-your-objective" tabindex="-1">Command: <code>/cm-start [your objective]</code> <a class="header-anchor" href="#command-cm-start-your-objective" aria-label="Permalink to &quot;Command: `/cm-start [your objective]`&quot;">​</a></h1><blockquote><p><strong>Role: Workflow Orchestrator</strong> — You assess complexity, select the right workflow depth, and drive execution from objective to production code.</p></blockquote><p>When this workflow is called, the AI Assistant should execute the following action sequence in the spirit of the <strong>CodyMaster Kit</strong>:</p><ol start="0"><li><strong>Load Working Memory:</strong> Per <code>_shared/helpers.md#Load-Working-Memory</code><ul><li>Update <code>CONTINUITY.md</code> → set Active Goal to the new objective</li></ul></li></ol><p>0.5. <strong>Skill Coverage Check (Adaptive Discovery):</strong> - Scan the objective for technologies, frameworks, or patterns mentioned - Cross-reference with <code>cm-skill-index</code> Layer 1 triggers - If gap detected → trigger Discovery Loop from <code>cm-skill-mastery</code> Part C: <code>npx skills find &quot;{keyword}&quot;</code> → review → ask user → install if approved - Log any discovered skills to <code>.cm-skills-log.json</code></p><p>0.7. <strong>Code Intelligence Setup (cm-codeintell):</strong> - <strong>ALWAYS:</strong> Run skeleton indexer → <code>bash scripts/index-codebase.sh</code> → <code>.cm/skeleton.md</code> - Read <code>.cm/skeleton.md</code> (~5K tokens) → instant codebase understanding - Count source files → determine intelligence level (MINIMAL/LITE/STANDARD/FULL) - IF level &gt;= LITE: generate architecture diagram → <code>.cm/architecture.mmd</code> - IF level &gt;= STANDARD: check CodeGraph → <code>codegraph status</code> → index if needed - IF level &gt;= FULL: also check qmd (cm-deep-search) - Log intelligence level to <code>CONTINUITY.md</code></p><ol><li><p><strong>Understand Requirements (Planning &amp; JTBD):</strong></p><ul><li>Read the objective provided in the <code>/cm-start</code> command.</li><li>Analyze requirements, ask clarifying questions if needed (apply <code>cm-planning</code>).</li><li>Consider multi-language support (i18n) from the start if the project requires it.</li></ul></li><li><p><strong>Detect Project Level:</strong> Per <code>_shared/helpers.md#Project-Level-Detection</code></p><ul><li>Analyze the objective to determine L0/L1/L2/L3 complexity</li><li>Present detected level and recommended skill chain to the user</li><li>Let user confirm or override the level</li></ul></li><li><p><strong>Execute Based on Level:</strong></p><p><strong>L0 (Micro):</strong> Code + Test only</p><ul><li>Skip planning. Apply <code>cm-tdd</code> directly → <code>cm-quality-gate</code></li></ul><p><strong>L1 (Small):</strong> Planning lite → Code → Deploy</p><ul><li>Apply <code>cm-planning</code> (lightweight implementation plan)</li><li>Apply <code>cm-tdd</code> + <code>cm-execution</code> → <code>cm-quality-gate</code></li></ul><p><strong>L2 (Medium):</strong> Full analysis flow</p><ul><li>Apply <code>cm-brainstorm-idea</code> if problem is ambiguous</li><li>Apply <code>cm-planning</code> (full implementation plan with task breakdown)</li><li>Create <code>cm-tasks.json</code> → launch RARV autonomous execution</li><li>Apply <code>cm-quality-gate</code> → <code>cm-safe-deploy</code></li></ul><p><strong>L3 (Large):</strong> Full + PRD + Architecture + Sprint</p><ul><li>Apply <code>cm-brainstorm-idea</code> (mandatory)</li><li>Apply <code>cm-planning</code> with FR/NFR requirement tracing</li><li>Sprint planning → <code>cm-tasks.json</code> with sprints</li><li>Apply <code>cm-execution</code> (Mode E: TRIZ-Parallel for speed)</li><li>Apply <code>cm-quality-gate</code> → <code>cm-safe-deploy</code></li></ul></li><li><p><strong>Track Progress:</strong></p><ul><li>Create or update <code>cm-tasks.json</code> by breaking the objective into specific tasks</li><li>Suggest <code>/cm-dashboard</code> for visual tracking</li><li>Suggest <code>/cm-status</code> for quick terminal summary</li></ul></li><li><p><strong>Complete:</strong> Per <code>_shared/helpers.md#Update-Continuity</code></p><ul><li>Record any new learnings or decisions made during this workflow</li></ul></li></ol><blockquote><p><strong>Note for AI:</strong> If this is a brand new project, suggest running <code>cm-project-bootstrap</code> first. If the working environment has a risk of accidentally switching accounts/projects, remind about <code>cm-identity-guard</code> (Per <code>_shared/helpers.md#Identity-Check</code>).</p></blockquote>',8)])])}const g=o(l,[["render",r]]);export{u as __pageData,g as default};
